#!/usr/bin/env bash
# libfdk-aac -- Fraunhofer AAC encoder (non-free). Enables --enable-nonfree in ffmpeg.
# Produces best-quality AAC output. Requires ffmpeg built with --enable-nonfree.
set -Eeuo pipefail
source "${DOTFILES_ROOT}/lib/bash-utilities.sh"
source "${DOTFILES_ROOT}/config/versions.conf"
source "${DOTFILES_ROOT}/lib/build.sh"

banner::print "build-libfdk-aac"
build::ensure_pkg_config_path

VERSION=$(build::resolve_version "LIBFDK_AAC")
build::already_installed "fdk-aac" "$VERSION" && exit 0

# GitHub tarballs lack autogenerated configure -- build::make_install runs autoreconf
URL="https://github.com/mstorsjo/fdk-aac/archive/refs/tags/v${VERSION}.tar.gz"
src_dir=$(build::fetch_tarball "fdk-aac" "$VERSION" "$URL")

build::make_install "$src_dir" \
  --enable-shared

build::verify_pkgconfig "fdk-aac"
log::info "libfdk-aac ${VERSION} done"
